const userOpsDetail = `-- name: UserOpsDetail :one
SELECT
    COALESCE((SELECT balance FROM user_balances WHERE user_balances.user_id = $1 AND currency = 'USD'), 0)::numeric AS balance_usd,
    COALESCE((SELECT reserved_balance FROM user_balances WHERE user_balances.user_id = $1 AND currency = 'USD'), 0)::numeric AS reserved_usd,
    COUNT(r.id) FILTER (WHERE r.status IN ('succeeded', 'failed')) AS request_total,
    COUNT(r.id) FILTER (WHERE r.status = 'succeeded') AS request_succeeded,
    COALESCE((
        SELECT SUM(le.amount) FROM ledger_entries le
        WHERE le.user_id = $1 AND le.entry_type = 'debit' AND le.currency = 'USD'
          AND ($2::timestamptz IS NULL OR le.created_at >= $2::timestamptz)
          AND ($3::timestamptz IS NULL OR le.created_at < $3::timestamptz)
    ), 0)::numeric AS consumption_usd
FROM request_records r
WHERE r.user_id = $1
  AND ($2::timestamptz IS NULL OR r.created_at >= $2::timestamptz)
  AND ($3::timestamptz IS NULL OR r.created_at < $3::timestamptz)
`

